class Solution:
    def minimumPairRemoval(self, nums):
        a = list(nums)
        ops = 0
        while True:
            n = len(a)
            sorted_ok = True
            for i in range(n - 1):
                if a[i] > a[i + 1]:
                    sorted_ok = False
                    break
            if sorted_ok:
                return ops
            best_i, best_sum = 0, a[0] + a[1]
            for i in range(1, n - 1):
                s = a[i] + a[i + 1]
                if s < best_sum:
                    best_sum = s
                    best_i = i
            a = a[:best_i] + [a[best_i] + a[best_i + 1]] + a[best_i + 2:]
            ops += 1

