class PairHeap {
    constructor() { this.a = []; }
    size() { return this.a.length; }
    static less(x, y) {
        if (x[0] !== y[0]) return x[0] < y[0];
        if (x[1] !== y[1]) return x[1] < y[1];
        return x[2] < y[2];
    }
    push(item) {
        const a = this.a;
        a.push(item);
        let idx = a.length - 1;
        while (idx > 0) {
            const p = (idx - 1) >> 1;
            if (!PairHeap.less(a[idx], a[p])) break;
            const tmp = a[p]; a[p] = a[idx]; a[idx] = tmp;
            idx = p;
        }
    }
    pop() {
        const a = this.a;
        const top = a[0];
        const last = a.pop();
        if (a.length > 0) {
            a[0] = last;
            let idx = 0;
            const len = a.length;
            while (true) {
                const l = 2 * idx + 1, r = 2 * idx + 2;
                let smallest = idx;
                if (l < len && PairHeap.less(a[l], a[smallest])) smallest = l;
                if (r < len && PairHeap.less(a[r], a[smallest])) smallest = r;
                if (smallest === idx) break;
                const tmp = a[idx]; a[idx] = a[smallest]; a[smallest] = tmp;
                idx = smallest;
            }
        }
        return top;
    }
}

var minimumPairRemoval = function(nums) {
    const n = nums.length;
    if (n <= 1) return 0;
    const val = nums.slice();
    const prev = new Array(n), nxt = new Array(n);
    for (let i = 0; i < n; i++) { prev[i] = i - 1; nxt[i] = i + 1; }
    const alive = new Array(n).fill(true);
    let bad = 0;
    for (let i = 0; i < n - 1; i++) if (val[i] > val[i + 1]) bad++;
    const heap = new PairHeap();
    for (let i = 0; i < n - 1; i++) heap.push([val[i] + val[i + 1], i, i + 1]);
    let ops = 0;
    while (bad > 0) {
        let s, i, j;
        while (true) {
            [s, i, j] = heap.pop();
            if (alive[i] && alive[j] && nxt[i] === j && val[i] + val[j] === s) break;
        }
        const p = prev[i];
        const q = nxt[j];
        const viOld = val[i], vjOld = val[j];
        if (viOld > vjOld) bad--;
        if (p !== -1 && val[p] > viOld) bad--;
        if (q < n && vjOld > val[q]) bad--;
        const newv = viOld + vjOld;
        val[i] = newv;
        alive[j] = false;
        nxt[i] = q;
        if (q < n) prev[q] = i;
        if (p !== -1) {
            if (val[p] > newv) bad++;
            heap.push([val[p] + newv, p, i]);
        }
        if (q < n) {
            if (newv > val[q]) bad++;
            heap.push([newv + val[q], i, q]);
        }
        ops++;
    }
    return ops;
};
